function escapeHtml(value: string): string {

  return value

    .replace(/&/g, '&amp;')

    .replace(/</g, '&lt;')

    .replace(/>/g, '&gt;')

    .replace(/"/g, '&quot;');

}



/** Remove table rows whose placeholder token was not substituted (optional fields). */

function stripOptionalRow(html: string, token: string): string {

  const escaped = token.replace(/[.*+?^$()|[\]\\]/g, '\\$&');

  return html.replace(new RegExp('<tr[^>]*>[\\s\\S]*?' + escaped + '[\\s\\S]*?</tr>', 'g'), '');

}



